define i1 @c0(i8 %x) {
  %tmp0 = and i8 %x, 3
  %ret = icmp sgt i8 %tmp0, %x
  ret i1 %ret
}

define i1 @c0(i8 %x) {
  %tmp0 = and i8 %x, 3
  %ret = icmp sle i8 %tmp0, %x
  ret i1 %ret
}

define i1 @src_is_mask_const_sgt(i8 %x_in) {
  %x = xor i8 %x_in, 123
  %and = and i8 %x, 7
  %r = icmp sgt i8 %x, %and
  ret i1 %r
}

define i1 @src_is_mask_const_sle(i8 %x_in) {
  %x = xor i8 %x_in, 123
  %and = and i8 %x, 31
  %r = icmp sle i8 %and, %x
  ret i1 %r
}

define i1 @src_is_mask_const_slt(i8 %x_in) {
  %x = xor i8 %x_in, 123
  %and = and i8 %x, 7
  %r = icmp slt i8 %x, %and
  ret i1 %r
}

